// =============================================
// Alert.Trigger — вызывается циклом oref_alert
// при каждом изменении Alert.Status
//
// Переменные:
//   $status   = Alert или No Alert
//   $category = числовой код (1-14)
//   $notify   = флаг 0/1
// =============================================

$status   = $this->getProperty('Status');
$notify   = (int)$this->getProperty('Notify');
$category = (int)$this->getProperty('Category');

// Категория 14: предупреждение (только звук, не тревога)
if ($category === 14) {
    if ((int)$this->getProperty('Last14Sounded') === 0) {
        sayTo($this->getProperty('Name') . ', ' . $this->getProperty('Instructions'), 2, 'home');
        $this->setProperty('Last14Sounded', 1);
    }
    return;
}

// Тревога
if ($status === 'Alert') {
    if ($notify === 0) {
        // === ДОБАВЬТЕ ВАШИ ДЕЙСТВИЯ ===
        // sayTo($this->getProperty('Name') . ', ' . $this->getProperty('Instructions'), 2, 'home');
        // getURLBackground('http://192.168.1.57/control?cmd=event,warning');
        $this->setProperty('Notify', 1);
    }
    return;
}

// Отбой
if ($status === 'No Alert') {
    if ($notify === 1) {
        // === ДОБАВЬТЕ ВАШИ ДЕЙСТВИЯ ===
        // sayTo('Отбой тревоги', 2, 'home');
        $this->setProperty('Notify', 0);
        $this->setProperty('Last14Sounded', 0);
    }
}
